<header class="page-head"><div><span class="eyebrow">Katalog</span><h1>Kategori</h1></div></header><div class="split"><section class="panel"><h2>Kategori tersedia</h2><div class="table-wrap" tabindex="0" aria-label="Daftar kategori, geser horizontal bila diperlukan"><table><thead><tr><th>Nama</th><th>Induk</th><th>Status</th><th>Aksi</th></tr></thead><tbody><?php foreach($items as $x):?><tr><td><?=e($x['name'])?></td><td><?=e($x['parent_name']??'—')?></td><td><?=$x['is_active']?'Aktif':'Nonaktif'?></td><td><form method="post" action="<?=url('/admin/categories/'.$x['id'])?>" onsubmit="return confirm('Hapus kategori ini? Produk di dalamnya tidak ikut terhapus.')"><?=csrf_field()?><input type="hidden" name="_method" value="DELETE"><button class="link-danger">Hapus</button></form></td></tr><?php endforeach?><?php if(!$items):?><tr><td colspan="4" class="empty-cell">Belum ada kategori. Tambahkan kategori pertama melalui form di samping.</td></tr><?php endif?></tbody></table></div></section><section class="panel sticky"><h2>Tambah kategori</h2><form method="post" action="<?=url('/admin/categories')?>" class="stack"><?=csrf_field()?><label>Nama kategori<input name="name" required></label><label>Kategori induk<select name="parent_id"><option value="0">Tanpa induk</option><?php foreach($items as $x):?><option value="<?=$x['id']?>"><?=e($x['name'])?></option><?php endforeach?></select></label><label>Deskripsi<textarea name="description"></textarea></label><label class="check"><input type="checkbox" name="is_active" value="1" checked> Tampilkan di toko</label><button class="button">Simpan kategori</button></form></section></div>
